  <svg viewBox="0 0 700 460" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="28" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">Today's Price Barely Moved, Yet ROC(30) Swung 104 Points</text>
    <text x="20" y="48" fill="#a1a1aa" font-size="13" font-family="sans-serif">April 2020: the illusion created as the base day (30 days back) crossed the crash window</text>
    <rect x="20" y="66" width="660" height="30" rx="6" fill="#1f2937"/>
    <text x="34" y="86" fill="#d4d4d8" font-size="12.5" font-weight="700" font-family="sans-serif">Date (today) · today's price · base day (30d ago) · base price · ROC(30)</text>
    <rect x="20" y="104" width="660" height="52" rx="8" fill="#18181b" stroke="#3f3f46"/>
    <text x="34" y="127" fill="#fafafa" font-size="13.5" font-family="sans-serif">Apr 5</text>
    <text x="110" y="127" fill="#fafafa" font-size="13.5" font-family="sans-serif">$6,640</text>
    <text x="230" y="127" fill="#a1a1aa" font-size="13" font-family="sans-serif">Mar 6</text>
    <text x="290" y="127" fill="#a1a1aa" font-size="13" font-family="sans-serif">$9,080</text>
    <rect x="560" y="112" width="100" height="34" rx="6" fill="#7f1d1d"/>
